  "marketing.standard.spec.contact.partnerLastName": "Cognome del partner.",
  "marketing.standard.spec.contact.partnerEmail": "Indirizzo e-mail del partner.",
  "marketing.standard.spec.contact.partnerPhone": "Numero di telefono del partner. Citare sempre.",
  "marketing.standard.spec.contact.source": "Da dove viene la pista. Esempi: sito web, Instagram, referral, esposizione di abiti da sposa.",
